export type ScheduleFrequency = 'daily' | 'weekly' | 'monthly';

export interface MonitoringSchedule {
  id: string;
  brandName: string;
  url: string;
  frequency: ScheduleFrequency;
  hour: string; // "HH:mm"
  dayOfWeek?: number; // 0-6 for weekly
  dayOfMonth?: number; // 1-31 for monthly
  emailNotify: boolean;
  paused: boolean;
  createdAt: string;
  lastRun: string | null;
  nextRun: string;
}

export interface ScheduledScanResult {
  id: string;
  scheduleId: string;
  brandName: string;
  url: string;
  executedAt: string;
  totalCitations: number;
  shareOfVoice: number;
  trend: number;
  status: 'completed' | 'failed';
}

import type {
  MonitoringSchedule,
  ScheduleFrequency,
  ScheduledScanResult,
} from '../types/scheduling';

const SCHEDULES_KEY = 'citedby_monitoring_schedules';
const HISTORY_KEY = 'citedby_scheduled_scan_history';

export function getSchedules(): MonitoringSchedule[] {
  const raw = localStorage.getItem(SCHEDULES_KEY);
  if (!raw) return [];
  try {
    return JSON.parse(raw) as MonitoringSchedule[];
  } catch {
    return [];
  }
}

function persistSchedules(schedules: MonitoringSchedule[]): void {
  localStorage.setItem(SCHEDULES_KEY, JSON.stringify(schedules));
}

export function saveSchedule(
  schedule: Omit<MonitoringSchedule, 'id' | 'createdAt' | 'nextRun' | 'lastRun'>
): MonitoringSchedule {
  const nextRun = computeNextRun(
    schedule.frequency,
    schedule.hour,
    schedule.dayOfWeek,
    schedule.dayOfMonth
  );

  const newSchedule: MonitoringSchedule = {
    ...schedule,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
    lastRun: null,
    nextRun,
  };

  const schedules = getSchedules();
  schedules.push(newSchedule);
  persistSchedules(schedules);

  return newSchedule;
}

export function deleteSchedule(id: string): void {
  const schedules = getSchedules().filter((s) => s.id !== id);
  persistSchedules(schedules);
}

export function togglePause(id: string): MonitoringSchedule | null {
  const schedules = getSchedules();
  const schedule = schedules.find((s) => s.id === id);
  if (!schedule) return null;

  schedule.paused = !schedule.paused;

  if (!schedule.paused) {
    schedule.nextRun = computeNextRun(
      schedule.frequency,
      schedule.hour,
      schedule.dayOfWeek,
      schedule.dayOfMonth
    );
  }

  persistSchedules(schedules);
  return schedule;
}

export function computeNextRun(
  freq: ScheduleFrequency,
  hour: string,
  dayOfWeek?: number,
  dayOfMonth?: number
): string {
  const [h, m] = hour.split(':').map(Number);
  const now = new Date();
  const next = new Date(now);

  next.setHours(h, m, 0, 0);

  if (freq === 'daily') {
    if (next <= now) {
      next.setDate(next.getDate() + 1);
    }
  } else if (freq === 'weekly' && dayOfWeek !== undefined) {
    const currentDay = next.getDay();
    let daysUntil = dayOfWeek - currentDay;
    if (daysUntil < 0 || (daysUntil === 0 && next <= now)) {
      daysUntil += 7;
    }
    next.setDate(next.getDate() + daysUntil);
  } else if (freq === 'monthly' && dayOfMonth !== undefined) {
    next.setDate(dayOfMonth);
    if (next <= now) {
      next.setMonth(next.getMonth() + 1);
      next.setDate(dayOfMonth);
    }
  }

  return next.toISOString();
}

export function getScheduledHistory(): ScheduledScanResult[] {
  const raw = localStorage.getItem(HISTORY_KEY);
  if (!raw) return [];
  try {
    return JSON.parse(raw) as ScheduledScanResult[];
  } catch {
    return [];
  }
}

function persistHistory(history: ScheduledScanResult[]): void {
  localStorage.setItem(HISTORY_KEY, JSON.stringify(history));
}

export function checkAndRunPendingScans(): ScheduledScanResult[] {
  const now = new Date();
  const schedules = getSchedules();
  const history = getScheduledHistory();
  const newResults: ScheduledScanResult[] = [];

  for (const schedule of schedules) {
    if (schedule.paused) continue;
    if (new Date(schedule.nextRun) > now) continue;

    const result: ScheduledScanResult = {
      id: crypto.randomUUID(),
      scheduleId: schedule.id,
      brandName: schedule.brandName,
      url: schedule.url,
      executedAt: now.toISOString(),
      totalCitations: Math.floor(Math.random() * 36) + 5, // 5-40
      shareOfVoice: Math.round((Math.random() * 40 + 5) * 100) / 100, // 5-45
      trend: Math.round((Math.random() * 40 - 15) * 100) / 100, // -15 to +25
      status: 'completed',
    };

    newResults.push(result);
    history.push(result);

    schedule.lastRun = now.toISOString();
    schedule.nextRun = computeNextRun(
      schedule.frequency,
      schedule.hour,
      schedule.dayOfWeek,
      schedule.dayOfMonth
    );
  }

  if (newResults.length > 0) {
    persistSchedules(schedules);
    persistHistory(history);
  }

  return newResults;
}

